object Solution { def realized_pnl(trades: Seq[Map[String, Any]]): Int = { val lots = scala.collection.mutable.ArrayBuffer[(Int, Int)](); var total = 0; for (trade <- trades) { if (asString(trade("side")) == "BUY") lots += ((asInt(trade("qty")), asInt(trade("price")))) else { var remaining = asInt(trade("qty")); val price = asInt(trade("price")); while (remaining > 0 && lots.nonEmpty) { val (lotQty, lotPrice) = lots.remove(0); val matched = math.min(remaining, lotQty); total += (price - lotPrice) * matched; remaining -= matched; if (matched < lotQty) lots.insert(0, (lotQty - matched, lotPrice)) } } }; total }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 }; private def asString(value: Any): String = value.toString }
